// build-competitor-clusters — Validate Upstream Inputs
// Checks all required upstream artifacts are present and well-formed.
// Resolves operating mode based on intake.competitor_urls.
//
// CLOUD MODE: all data arrives inline via n8n pipeline.
//             No filesystem access required.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const storeProfile = input.store_profile;
const marketIntelligence = input.market_intelligence;
const intakePayload = input.normalized_intake_payload;
const runtimeConfig = input.runtime_config;
const projectId = input.project_id;

// Propagate cloud_mode from upstream
if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) cloudMode = true;

// Required presence checks
if (!storeProfile || !storeProfile.store_id) {
  throw new Error('MISSING_ARTIFACT: store_profile with store_id is required. Run build-store-profile first.');
}
if (!marketIntelligence) {
  throw new Error('MISSING_ARTIFACT: market_intelligence is required. Run build-market-intelligence first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

// Required store_profile fields
const profileRequired = ['store_id', 'vertical', 'price_positioning'];
const profileMissing = profileRequired.filter(function(f) { return !storeProfile[f]; });
if (profileMissing.length > 0) {
  throw new Error('MISSING_ARTIFACT: store_profile missing required fields: ' + profileMissing.join(', '));
}

// Required market_intelligence fields
if (!marketIntelligence.market_category || !String(marketIntelligence.market_category).trim()) {
  throw new Error('MISSING_ARTIFACT: market_intelligence.market_category is required and must be non-empty.');
}
if (!Array.isArray(marketIntelligence.competitor_types) || marketIntelligence.competitor_types.length === 0) {
  throw new Error('MISSING_ARTIFACT: market_intelligence.competitor_types must be a non-empty array.');
}
if (!Array.isArray(marketIntelligence.positioning_goals) || marketIntelligence.positioning_goals.length === 0) {
  throw new Error('MISSING_ARTIFACT: market_intelligence.positioning_goals must be a non-empty array.');
}

// competitor_urls: may be absent, null, or empty — all valid (archetype mode)
const rawUrls = intakePayload.competitor_urls;
const competitorUrls = Array.isArray(rawUrls)
  ? rawUrls.filter(function(u) { return u && typeof u === 'string' && u.trim(); })
  : [];

// Resolve operating mode
let mode;
if (competitorUrls.length >= 2) {
  mode = 'url-seeded';
} else if (competitorUrls.length === 1) {
  mode = 'hybrid';
} else {
  mode = 'archetype';
}

console.log('build-competitor-clusters: mode=' + mode + ', competitor_urls_count=' + competitorUrls.length);

return [{
  json: {
    project_id: projectId,
    runtime_config: runtimeConfig,
    store_profile: storeProfile,
    market_intelligence: marketIntelligence,
    normalized_intake_payload: intakePayload,
    brand_positioning: input.brand_positioning || null,
    competitor_urls: competitorUrls,
    mode: mode,
    cloud_mode: cloudMode,
  },
}];

// build-competitor-clusters — Build LLM Clustering Prompt
// Assembles the structured LLM prompt based on operating mode:
//   url-seeded  (>=2 URLs): group user-provided URLs into 2–4 clusters
//   hybrid      (1 URL):    1 URL-seeded cluster + 1–2 archetype clusters
//   archetype   (0 URLs):   2–3 pure archetype clusters with ARCHETYPE-PLACEHOLDER
//
// Evidence boundary: no live crawling, no external APIs.
// All cluster content is LLM inference — not verified competitor research.
// Phase 16: Expanded cluster schema to request new optional fields.

const input = $input.first().json;
const storeProfile = input.store_profile;
const mi = input.market_intelligence;
const competitorUrls = input.competitor_urls || [];
const mode = input.mode;
const cloudMode = input.cloud_mode || false;

// Store context
const vertical = storeProfile.vertical || 'unknown';
const pricePositioning = storeProfile.price_positioning || 'unknown';
const primaryMarket = storeProfile.primary_market || 'unknown';
const marketCategory = mi.market_category || 'unknown';
const positioningGoals = (mi.positioning_goals || []).slice(0, 3).join('; ');

// Competitor types from market intelligence — primary clustering seed
const competitorTypesBlock = (mi.competitor_types || []).slice(0, 6).map(function(ct) {
  const strengths = (ct.strengths || []).slice(0, 2).join(', ');
  const weaknesses = (ct.weaknesses || []).slice(0, 2).join(', ');
  return '  - ' + ct.type_name + ': ' + (ct.description || '') +
    (strengths ? ' | Strengths: ' + strengths : '') +
    (weaknesses ? ' | Weaknesses: ' + weaknesses : '');
}).join('\n');

// Enums (must match schemas/competitor-cluster.schema.json exactly)
const CLUSTER_ROLE_ENUM = [
  'premium-brand-cluster', 'value-cluster', 'editorial-cluster',
  'marketplace-like-cluster', 'trend-driven-cluster',
  'problem-solver-cluster', 'specialist-cluster'
];
const PATTERN_TYPE_ENUM = [
  'layout', 'navigation', 'pdp-structure', 'collection-strategy',
  'seo-pattern', 'aeo-pattern', 'trust-pattern', 'media-pattern',
  'motion-pattern', 'offer-pattern', 'copy-pattern'
];

// Mode-specific instructions
let modeInstruction;
if (mode === 'url-seeded') {
  modeInstruction = [
    'MODE: URL-SEEDED',
    'User-provided competitor URLs (use as naming/labeling hints ONLY — do NOT fetch, crawl, or research):',
    competitorUrls.map(function(u, i) { return '  ' + (i + 1) + '. ' + u; }).join('\n'),
    '',
    'Group these URLs into 2–4 clusters based on their apparent type, using the competitor_types above as a reference framework.',
    'Each cluster\'s competitor_examples must only include URLs from the list above — do NOT invent or add URLs.',
    'If a URL cannot be confidently assigned to a known archetype, place it in the most fitting cluster and note the uncertainty in that cluster\'s notes field.',
  ].join('\n');
} else if (mode === 'hybrid') {
  modeInstruction = [
    'MODE: HYBRID (exactly 1 URL provided)',
    'User-provided competitor URL (use as naming/labeling hint ONLY — do NOT fetch, crawl, or research):',
    '  1. ' + competitorUrls[0],
    '',
    'Generate:',
    '  - 1 URL-seeded cluster for this URL (competitor_examples: use only the URL above)',
    '  - 1–2 archetype clusters for the remaining competitive landscape',
    '    (competitor_examples: url must be "ARCHETYPE-PLACEHOLDER" for all archetype cluster entries)',
    '',
    'Label each cluster with its mode in the notes field: URL-SEEDED or ARCHETYPE-MODE.',
  ].join('\n');
} else {
  modeInstruction = [
    'MODE: ARCHETYPE',
    'No competitor URLs were provided by the user.',
    'Generate 2–3 representative archetype clusters based on the competitor_types below.',
    'For ALL competitor_examples entries, set url to "ARCHETYPE-PLACEHOLDER".',
    'Clearly indicate in each entry\'s notes that it is a hypothetical archetype, not a real competitor.',
  ].join('\n');
}

const prompt = [
  'You are a commerce strategy analyst. Generate a JSON array of competitor clusters for a ' + vertical + ' store.',
  '',
  'STORE CONTEXT:',
  '- Vertical: ' + vertical,
  '- Price positioning: ' + pricePositioning,
  '- Primary market: ' + primaryMarket,
  '- Market category: ' + marketCategory,
  '- Positioning goals: ' + positioningGoals,
  '',
  'MARKET INTELLIGENCE — COMPETITOR TYPES (primary clustering seed):',
  competitorTypesBlock,
  '',
  modeInstruction,
  '',
  'OUTPUT REQUIREMENTS:',
  'Return a JSON array at the root level (no wrapper object). Each element is a competitor cluster with ALL of these required fields:',
  '',
  '1. cluster_name (string) — descriptive name for this cluster archetype',
  '2. cluster_role (string) — MUST be exactly one of: ' + CLUSTER_ROLE_ENUM.join(', '),
  '3. description (string) — this cluster\'s market role and target audience',
  '4. competitor_examples (array, minItems: 1) — each item: { "name": string, "url": string, "notes"?: string, "competitor_type_classification"?: string, "price_tier"?: string, "brand_style_note"?: string }',
  '   - URL-seeded clusters: url must be from the user-provided list ONLY',
  '   - Archetype/hybrid-archetype clusters: url must be "ARCHETYPE-PLACEHOLDER"',
  '5. shared_strengths (array of strings, minItems: 1) — inferred typical strengths of this cluster',
  '6. shared_weaknesses (array of strings, minItems: 1) — inferred typical weaknesses',
  '7. shared_patterns (array, minItems: 1) — each item: { "pattern_type": string, "description": string, "why_it_works": string, "risk_if_overused"?: string }',
  '   - pattern_type MUST be exactly one of: ' + PATTERN_TYPE_ENUM.join(', '),
  '8. non_copyable_elements (array of strings, minItems: 1) — elements this cluster relies on that the store should NOT copy',
  '9. adaptation_opportunities (array of strings, minItems: 1) — how to adapt strengths without inheriting weaknesses',
  '',
  'OPTIONAL per cluster (include when meaningful):',
  '- competitor_type_classification: "direct|indirect|substitute|aspirational|mixed"',
  '- price_tier: "budget|mass-market|mass-premium|premium|luxury|mixed|unknown"',
  '- brand_style: brief string describing this cluster\'s visual/brand style',
  '- product_breadth: "single-product|narrow|moderate|broad|marketplace-scale"',
  '- trust_signals_used: array of strings (trust signal types this cluster relies on)',
  '- strategic_summary: 1-2 sentence string — what this cluster means for the store\'s strategy',
  '- seo_relevance (string[]), aeo_relevance (string[]), recommended_use_cases (string[]), notes (string)',
  '',
  'For competitor_examples items, you may also include:',
  '- competitor_type_classification: string (e.g. "direct", "indirect")',
  '- price_tier: string (e.g. "premium", "mass-market")',
  '- brand_style_note: string (brief note on this specific example\'s brand style)',
  '',
  'EVIDENCE BOUNDARY:',
  '- All analysis is LLM inference — NOT verified competitor research.',
  '- Do not invent traffic figures, conversion rates, revenue, or factual competitive metrics.',
  '- Do not add URLs not explicitly provided by the user.',
  '- Do not fetch, crawl, or research any URL.',
  '',
  'Return ONLY valid JSON — no markdown code fences, no preamble, no explanation.',
].join('\n');

return [{
  json: {
    llm_prompt: prompt,
    project_id: input.project_id,
    runtime_config: input.runtime_config,
    store_profile: storeProfile,
    market_intelligence: mi,
    competitor_urls: competitorUrls,
    mode: mode,
    cloud_mode: cloudMode,
  },
}];

// build-competitor-clusters — Parse, Apply Evidence Boundaries, Validate, and Write
// Phase 16: Added runtime envelope. New optional cluster fields passed through.
//
// Steps:
//   1. Parse LLM JSON array response
//   2. Apply evidence boundary enforcement per cluster (ARCHETYPE-PLACEHOLDER / URL stripping)
//   3. Inline schema validation (both modes — enum checks, required fields, minItems)
//   4. AJV full schema validation (self-hosted only)
//   5. Write competitor-clusters.json artifact (self-hosted only)
//   6. Return competitor_clusters inline (both modes) with envelope
//
// CLOUD MODE: steps 4 and 5 are skipped. Inline validation (step 3) always runs.

function buildRunId() {
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  const rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

let fs, path;
let cloudMode = false;
try {
  fs = require('fs');
  path = require('path');
} catch (_e) {
  cloudMode = true;
}

const llmOutput = $input.first().json;
const upstream = $node['Build LLM Clustering Prompt'].json;

if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId = upstream.project_id;
const runtimeConfig = upstream.runtime_config;
const storeProfile = upstream.store_profile;
const competitorUrls = upstream.competitor_urls || [];
const mode = upstream.mode;

// Extract text from OpenAI node (simplifyOutput: true → message.content)
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

// ─── Step 1: Parse LLM response ───────────────────────────────────────────────
let clusters;
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) {
    clusters = parsed;
  } else if (parsed && Array.isArray(parsed.clusters)) {
    // Handle wrapped { clusters: [...] } — extract array
    clusters = parsed.clusters;
  } else if (parsed && typeof parsed === 'object') {
    // Single object — wrap in array
    clusters = [parsed];
  } else {
    throw new Error('Unexpected response shape.');
  }
} catch (err) {
  throw new Error(
    'PARSE_ERROR: Failed to parse LLM response as JSON array: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

if (!Array.isArray(clusters) || clusters.length === 0) {
  throw new Error('PARSE_ERROR: LLM returned empty or non-array competitor clusters. Cannot proceed.');
}

// ─── Step 2: Apply evidence boundary enforcement per cluster ───────────────────
const now = new Date().toISOString();

clusters = clusters.map(function(cluster, idx) {
  // Determine per-cluster mode (relevant in hybrid mode)
  let clusterMode = mode;
  if (mode === 'hybrid') {
    const exampleUrls = (cluster.competitor_examples || []).map(function(e) { return e.url || ''; });
    const hasUserUrl = competitorUrls.some(function(u) { return exampleUrls.includes(u); });
    clusterMode = hasUserUrl ? 'url-seeded' : 'archetype';
  }

  // Enforce ARCHETYPE-PLACEHOLDER in archetype clusters
  if (clusterMode === 'archetype') {
    cluster.competitor_examples = (cluster.competitor_examples || []).map(function(ex) {
      if (ex.url && ex.url !== 'ARCHETYPE-PLACEHOLDER' && !competitorUrls.includes(ex.url)) {
        console.warn('ARCHETYPE_ENFORCED [cluster ' + idx + ']: Replaced invented URL "' + ex.url + '" with ARCHETYPE-PLACEHOLDER');
        return {
          name: ex.name || ('Typical ' + (cluster.cluster_role || 'competitor') + ' in ' + (storeProfile.vertical || 'this vertical')),
          url: 'ARCHETYPE-PLACEHOLDER',
          notes: (ex.notes ? ex.notes + ' ' : '') + 'ARCHETYPE-MODE: No real competitor URL provided. Hypothetical archetype example.',
          competitor_type_classification: ex.competitor_type_classification || undefined,
          price_tier: ex.price_tier || undefined,
          brand_style_note: ex.brand_style_note || undefined,
        };
      }
      return ex;
    });
    // Guarantee at least one entry
    if (!cluster.competitor_examples || cluster.competitor_examples.length === 0) {
      cluster.competitor_examples = [{
        name: 'Typical ' + (cluster.cluster_role || 'competitor') + ' in ' + (storeProfile.vertical || 'this vertical'),
        url: 'ARCHETYPE-PLACEHOLDER',
        notes: 'ARCHETYPE-MODE: No real competitor URL provided. Hypothetical archetype example.',
      }];
    }
  }

  // Strip invented URLs in url-seeded clusters
  if (clusterMode === 'url-seeded') {
    cluster.competitor_examples = (cluster.competitor_examples || []).filter(function(ex) {
      if (ex.url === 'ARCHETYPE-PLACEHOLDER') return true;
      if (competitorUrls.includes(ex.url)) return true;
      console.warn('URL_SEEDED_ENFORCED [cluster ' + idx + ']: Removed invented URL "' + ex.url + '"');
      return false;
    });
    // Fallback if all examples were stripped
    if (cluster.competitor_examples.length === 0) {
      cluster.competitor_examples = [{
        name: 'User-provided competitor',
        url: competitorUrls[0] || 'ARCHETYPE-PLACEHOLDER',
        notes: 'URL-SEEDED: URL provided by user via intake.',
      }];
    }
  }

  // Set evidence boundary notes field
  const clusterLabel = clusterMode === 'url-seeded' ? 'URL-SEEDED' : 'ARCHETYPE-MODE';
  cluster.notes = [
    'COMPETITOR CLUSTER — ' + clusterLabel + ': All strength, weakness, pattern, and opportunity analysis is LLM inference.',
    'No live competitor research was performed.',
    'Treat all values as planning hypotheses requiring human verification.',
    'Generated: ' + now,
    cluster.notes ? 'Context: ' + cluster.notes : null,
  ].filter(Boolean).join(' | ');

  return cluster;
});

// ─── Step 3: Inline schema validation (runs in both modes) ────────────────────
const CLUSTER_ROLE_ENUM = [
  'premium-brand-cluster', 'value-cluster', 'editorial-cluster',
  'marketplace-like-cluster', 'trend-driven-cluster',
  'problem-solver-cluster', 'specialist-cluster'
];
const PATTERN_TYPE_ENUM = [
  'layout', 'navigation', 'pdp-structure', 'collection-strategy',
  'seo-pattern', 'aeo-pattern', 'trust-pattern', 'media-pattern',
  'motion-pattern', 'offer-pattern', 'copy-pattern'
];
const REQUIRED_CLUSTER_FIELDS = [
  'cluster_name', 'cluster_role', 'description', 'competitor_examples',
  'shared_strengths', 'shared_weaknesses', 'shared_patterns',
  'non_copyable_elements', 'adaptation_opportunities'
];
const ARRAY_FIELDS = [
  'competitor_examples', 'shared_strengths', 'shared_weaknesses',
  'shared_patterns', 'non_copyable_elements', 'adaptation_opportunities'
];

const validationErrors = [];

clusters.forEach(function(cluster, idx) {
  const label = 'Cluster[' + idx + '] (' + (cluster.cluster_name || 'unnamed') + ')';

  // Required fields
  REQUIRED_CLUSTER_FIELDS.forEach(function(f) {
    if (cluster[f] === undefined || cluster[f] === null || cluster[f] === '') {
      validationErrors.push(label + ': missing required field "' + f + '"');
    }
  });

  // cluster_role enum
  if (cluster.cluster_role && !CLUSTER_ROLE_ENUM.includes(cluster.cluster_role)) {
    validationErrors.push(label + ': cluster_role "' + cluster.cluster_role + '" not in enum. Must be one of: ' + CLUSTER_ROLE_ENUM.join(', '));
  }

  // Array fields minItems: 1
  ARRAY_FIELDS.forEach(function(f) {
    if (!Array.isArray(cluster[f]) || cluster[f].length === 0) {
      validationErrors.push(label + ': "' + f + '" must be a non-empty array (minItems: 1)');
    }
  });

  // competitor_examples items: name + url required
  if (Array.isArray(cluster.competitor_examples)) {
    cluster.competitor_examples.forEach(function(ex, ei) {
      if (!ex.name || typeof ex.name !== 'string' || !ex.name.trim()) {
        validationErrors.push(label + '.competitor_examples[' + ei + ']: missing required field "name"');
      }
      if (!ex.url || typeof ex.url !== 'string' || !ex.url.trim()) {
        validationErrors.push(label + '.competitor_examples[' + ei + ']: missing required field "url"');
      }
    });
  }

  // shared_patterns items: pattern_type enum + required sub-fields
  if (Array.isArray(cluster.shared_patterns)) {
    cluster.shared_patterns.forEach(function(p, pi) {
      const pLabel = label + '.shared_patterns[' + pi + ']';
      if (!p.pattern_type || !PATTERN_TYPE_ENUM.includes(p.pattern_type)) {
        validationErrors.push(pLabel + ': pattern_type "' + p.pattern_type + '" not in enum. Must be one of: ' + PATTERN_TYPE_ENUM.join(', '));
      }
      if (!p.description || typeof p.description !== 'string' || !p.description.trim()) {
        validationErrors.push(pLabel + ': missing required field "description"');
      }
      if (!p.why_it_works || typeof p.why_it_works !== 'string' || !p.why_it_works.trim()) {
        validationErrors.push(pLabel + ': missing required field "why_it_works"');
      }
    });
  }
});

if (validationErrors.length > 0) {
  throw new Error('SCHEMA_VALIDATION_FAILED: ' + validationErrors.join(' | '));
}

// ─── Step 4: AJV full validation — self-hosted only ──────────────────────────
const cloudWarnings = [];
if (!cloudMode) {
  try {
    const Ajv = require('ajv/dist/ajv.js') || require('ajv');
    const ajv = new Ajv({ allErrors: true, strict: false });
    const schemaFile = path.join(runtimeConfig.ajv_schema_path, 'competitor-cluster.schema.json');
    const schema = JSON.parse(fs.readFileSync(schemaFile, 'utf8'));
    const validate = ajv.compile(schema);
    clusters.forEach(function(cluster, idx) {
      const valid = validate(cluster);
      if (!valid) {
        const errs = (validate.errors || []).map(function(e) { return e.instancePath + ' ' + e.message; }).join('; ');
        throw new Error('AJV_VALIDATION_FAILED at cluster[' + idx + ']: ' + errs);
      }
    });
  } catch (e) {
    if (e.message && e.message.startsWith('AJV_VALIDATION_FAILED')) throw e;
    cloudWarnings.push('AJV schema validation skipped: ' + e.message);
  }
} else {
  cloudWarnings.push('AJV schema validation skipped — cloud mode (no local schema files). Inline validation passed.');
}

// ─── Step 5: Write artifact — self-hosted only ───────────────────────────────
let artifactPath = null;
if (!cloudMode) {
  try {
    const projectDir = path.join(runtimeConfig.project_root, projectId);
    if (!fs.existsSync(projectDir)) fs.mkdirSync(projectDir, { recursive: true });
    artifactPath = path.join(projectDir, 'competitor-clusters.json');
    fs.writeFileSync(artifactPath, JSON.stringify(clusters, null, 2), 'utf8');
  } catch (e) {
    cloudWarnings.push('Artifact write skipped: ' + e.message);
  }
} else {
  cloudWarnings.push('Artifact write skipped — cloud mode (no filesystem).');
}

const clusterCount = clusters.length;
console.log('build-competitor-clusters: completed. mode=' + mode + ', clusters=' + clusterCount + ', cloud=' + cloudMode);

// ─── Build runtime envelope ───────────────────────────────────────────────────
const runId = buildRunId();
const executionTs = new Date().toISOString();

const envelope = {
  runtime: {
    run_id: runId,
    phase_id: 'build-competitor-clusters',
    execution_ts: executionTs,
    cloud_mode: cloudMode,
    env: cloudMode ? 'cloud-smoke' : (runtimeConfig.env || 'dev'),
    schema_version: '1.0'
  },
  store: {
    project_id: projectId,
    artifact_name: 'competitor-clusters',
    artifact_path: artifactPath
  },
  status: {
    code: 'SUCCESS',
    completed_at: executionTs,
    fatal_errors: [],
    warnings: cloudWarnings,
    retryable: false
  },
  diagnostics: {
    input_summary: {
      project_id: projectId,
      vertical: storeProfile.vertical,
      primary_market: storeProfile.primary_market,
      price_positioning: storeProfile.price_positioning,
      mode: mode,
      competitor_urls_count: competitorUrls.length
    },
    output_summary: {
      cluster_count: clusterCount,
      mode: mode,
      has_new_optional_fields: clusters.some(function(c) { return c.strategic_summary || c.competitor_type_classification; })
    },
    validation: {
      schema_ref: 'schemas/competitor-cluster.schema.json',
      result: cloudMode ? 'SKIPPED' : (cloudWarnings.some(function(w) { return w.includes('AJV schema validation skipped'); }) ? 'SKIPPED' : 'PASS'),
      errors: [],
      warnings: cloudMode ? ['AJV validation skipped — cloud mode'] : []
    },
    lineage: {
      upstream_phases: ['resolve-runtime-config', 'intake-store-input', 'build-store-profile', 'build-market-intelligence', 'build-brand-positioning'],
      upstream_artifacts: ['store_profile', 'market_intelligence', 'normalized_intake_payload']
    },
    missing_data: []
  }
};

return [{
  json: {
    project_id: projectId,
    artifact_name: 'competitor-clusters',
    artifact_path: artifactPath,
    competitor_clusters: clusters,
    cluster_count: clusterCount,
    mode: mode,
    runtime_config: runtimeConfig,
    status: 'SUCCESS',
    cloud_mode: cloudMode,
    cloud_warnings: cloudWarnings,
    notes: [],
    envelope: envelope,
  },
}];
